// Enhanced Hero Section with Dynamic 3D Effects
const Hero = styled(GlassContainer)`
  text-align: center;
  padding: 5rem 2rem;
  margin-bottom: 4rem;
  position: relative;
  overflow: hidden;
  transform-style: preserve-3d;
  
  /* Enhanced background animation */
  &::before {
    content: '';
    position: absolute;
    top: -60%;
    left: -60%;
    width: 220%;
    height: 220%;
    background: ${props => props.theme.colors.background === '#ffffff' 
      ? 'conic-gradient(from 0deg, rgba(59, 130, 246, 0.1) 0%, rgba(255, 107, 53, 0.15) 33%, rgba(16, 185, 129, 0.1) 66%, rgba(139, 92, 246, 0.1) 100%)'
      : 'conic-gradient(from 0deg, rgba(255, 107, 53, 0.15) 0%, rgba(59, 130, 246, 0.1) 33%, rgba(16, 185, 129, 0.1) 66%, rgba(255, 107, 53, 0.1) 100%)'};
    animation: float 25s ease-in-out infinite;
    opacity: 0.6;
  }

  /* Floating particles effect */
  &::after {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background-image: 
      radial-gradient(circle at 20% 20%, rgba(255, 107, 53, 0.1) 1px, transparent 1px),
      radial-gradient(circle at 80% 80%, rgba(59, 130, 246, 0.1) 1px, transparent 1px),
      radial-gradient(circle at 40% 80%, rgba(16, 185, 129, 0.1) 1px, transparent 1px);
    background-size: 50px 50px, 80px 80px, 60px 60px;
    animation: particles 30s linear infinite;
    opacity: ${props => props.theme.colors.background === '#ffffff' ? '0.4' : '0.3'};
  }

  @keyframes float {
    0%, 100% { transform: translate(-50%, -50%) rotate(0deg) scale(1); }
    25% { transform: translate(-50%, -50%) rotate(90deg) scale(1.1); }
    50% { transform: translate(-50%, -50%) rotate(180deg) scale(1); }
    75% { transform: translate(-50%, -50%) rotate(270deg) scale(1.1); }
  }

  @keyframes particles {
    0% { transform: translateY(0px); }
    100% { transform: translateY(-20px); }
  }

  /* 3D hover effect */
  &:hover {
    transform: translateY(-2px) rotateX(1deg);
    transition: all 0.6s cubic-bezier(0.4, 0, 0.2, 1);
  }
`;

